// And groups predicates with the AND operator between them.
func And(predicates ...predicate.CommissionReward) predicate.CommissionReward {
	return predicate.CommissionReward(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.CommissionReward) predicate.CommissionReward {
	return predicate.CommissionReward(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.CommissionReward) predicate.CommissionReward {
	return predicate.CommissionReward(sql.NotPredicates(p))
}
